def token_f1(ref, cand):
    ref_set = set(ref)
    cand_set = set(cand)
    common = ref_set & cand_set
    if not common:
        return 0.0
    prec = len(common)/len(cand_set) if cand_set else 0
    rec = len(common)/len(ref_set) if ref_set else 0
    if prec+rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

